mapper.select:
SELECT * FROM ( SELECT ROWNUM RN, A.* FROM ( SELECT APT_CMPLEX_NO AS aptCmplexNo, APT_CMPLEX_NM AS aptCmplexNm, SIDO_NM AS sidoNm, SIGUNGU_NM AS sigunguNm, EMD_NM AS emdNm, DOROJUSO AS dorojuso, UNIT_CNT AS unitCnt, DONG_CNT AS dongCnt, BLD_YR AS bldYr FROM APT_COMPLEX WHERE SIDO_NM = #{sidoNm}
AND ( APT_CMPLEX_NM LIKE '%' || #{keyword} || '%' OR DOROJUSO LIKE '%' || #{keyword} || '%' )
ORDER BY APT_CMPLEX_NM ASC ) A WHERE ROWNUM <= #{pagingVO.endRow} ) WHERE RN >= #{pagingVO.startRow}

select APT_CMPLEX_NO
from MGMT_OFFICE
where MGMT_OFC_NO = #{mgmtOfcNo}
